// app/api/auth/[...nextauth]/route.js
import NextAuth from 'next-auth';

const handler = NextAuth({
  providers: [
    {
      id: 'credentials',
      name: 'Credentials',
      credentials: {
        email: { label: 'Email', type: 'text' },
        password: { label: 'Parol', type: 'password' }
      },
      async authorize(credentials) {
        // Mock user
        if (credentials.email === 'user@example.com' && credentials.password === '123') {
          return { id: '1', name: 'Test User', email: 'user@example.com' };
        }
        return null;
      }
    }
  ]
});

export { handler as GET, handler as POST };

console.log('Credentials provider yaradıldı');

// app/api/auth/[...nextauth]/route.js
import NextAuth from 'next-auth';
import GoogleProvider from 'next-auth/providers/google';

const handler = NextAuth({
  providers: [
    GoogleProvider({
      clientId: process.env.GOOGLE_CLIENT_ID,
      clientSecret: process.env.GOOGLE_CLIENT_SECRET
    })
  ]
});

export { handler as GET, handler as POST };

console.log('Google provider yaradıldı');

const handler = NextAuth({
  session: {
    strategy: 'jwt' // və ya 'database'
  },
  callbacks: {
    async session({ session, token }) {
      session.user.id = token.sub;
      return session;
    }
  }
});

console.log('JWT sessiya yaradıldı');

'use client';

import { useSession } from 'next-auth/react';

export default function Profile() {
  const { data: session, status } = useSession();

  if (status === 'loading') return <p>Yüklənir...</p>;
  if (!session) return <p>Giriş edin</p>;

  return <p>Salam, {session.user.name}</p>;
}

